# Secure preprocessing
preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

# Security: Validate file type
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'webp'}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

# Security: Input validation
def validate_input(image_data):
    if not image_data:
        return False
    if len(image_data) > 10 * 1024 * 1024:  # 10MB limit
        return False
    return True

# Security: Hash-based input validation
def get_file_hash(image_data):
    return hashlib.sha256(image_data).hexdigest()

@app.route('/classify', methods=['POST'])
def classify_image():
    try:
        # Validate input
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
        
        file = request.files['image']
        
        if file.filename == '':
            return jsonify({'error': 'No image selected'}), 400
        
        if not allowed_file(file.filename):
            return jsonify({'error': 'Invalid file type'}), 400
        
        # Read image data
        image_data = file.read()
        
        # Validate input size
        if not validate_input(image_data):
            return jsonify({'error': 'Invalid input'}), 400
        
        # Security: Check hash for known malicious patterns
        image_hash = get_file_hash(image_data)
        # In production, check against known malicious hashes
        
        # Open image
        image = Image.open(io.BytesIO(image_data)).convert('RGB')
        
        # Preprocess image
        input_tensor = preprocess(image)
        input_batch = input_tensor.unsqueeze(0)
        
        # Run inference
        with torch.no_grad():
            output = model(input_batch)
            probabilities = F.softmax(output, dim=1)
            confidence, predicted = torch.max(probabilities, 1)
            
        # Get class label
        class_idx = predicted.item()
        confidence_score = confidence.item()
        class_label = CLASS_LABELS[class_idx]
        
        # Security: Return only necessary information
        return jsonify({
            'class': class_label,
            'confidence': round(confidence_score, 4)
        })
        
    except Exception as e:
        # Security: Don't expose internal errors
        return jsonify({'error': 'Internal server error'}), 500

